/**
 Calculates the lattice expectation value of all operators in the model
 @param ops list of names of operators to compute the averages of
 @returns an array of (string, double) giving the average for each lattice
 operator
 */
vector<pair<string, double>>
lattice_model_instance::averages(const vector<string> &_ops) {
  if (average_solved)
    return ave;
  if (_ops.size() == 0)
    ops = model->one_body_ops;
  else {
    ops.clear();
    ops.reserve(_ops.size());
    for (int i = 0; i < _ops.size(); i++) {
      if (model->term[_ops[i]]->is_interaction == false)
        ops.push_back(model->term[_ops[i]]);
    }
  }
  if (!gf_solved)
    Green_function_solve();
  double accur_OP = global_double("accur_OP");
  bool periodized_averages = global_bool("periodized_averages");

  // frequency integral
  vector<double> Iv(ops.size());
  // lambda function
  if (periodized_averages) {
    auto F = [this](Complex w, vector3D<double> &k, const int *nv,
                    double *I) mutable { average_integrand_per(w, k, nv, I); };
    QCM::wk_integral(model->spatial_dimension, F, Iv, accur_OP,
                     global_bool("verb_integrals"));
  } else {
    auto F = [this](Complex w, vector3D<double> &k, const int *nv,
                    double *I) mutable { average_integrand(w, k, nv, I); };
    QCM::wk_integral(model->spatial_dimension, F, Iv, accur_OP,
                     global_bool("verb_integrals"));
  }

  size_t i = 0;
  ave.resize(ops.size());
  for (auto &op : ops) {
    if (periodized_averages)
      Iv[i] *= model->Lc;
    if (model->mixing == HS_mixing::full) {
      Iv[i] += op->nambu_correction_full;
      Iv[i] *= 0.5;
    } else if ((model->mixing & HS_mixing::anomalous) == HS_mixing::anomalous)
      Iv[i] += op->nambu_correction;
    ave[i] = {op->name, Iv[i] * op->norm};
    i++;
  }
  average_solved = true;

  // computing the kinetic energy
  E_kin = 0.0;
  i = 0;
  for (auto &op : ops) {
    if (op->name != "mu")
      E_kin += Iv[i] * params.at(op->name);
    i++;
  }
  E_kin /= model->Lc;

  return ave;
}

