/**
 integrands in the calculation of lattice averages
 @param w frequency
 @param k wavevector
 @param nv number of components
 @param I values of the components of the integrand
 */
void lattice_model_instance::average_integrand_per(Complex w,
                                                   vector3D<double> &k,
                                                   const int *nv, double *I) {

  const double w_offset = 2.0;
  Complex G_pole = 1.0 / (w - w_offset);

  Green_function G = cluster_Green_function(w, false, false);
  vector3D<double> k_red = model->superdual.to(model->physdual.from(k));

  Green_function_k K(G, k_red);
  periodized_Green_function(K);
  K.g.add(-G_pole); // regulates the Green function at high frequency (subtracts
                    // G_pole times the identity matrix)

  size_t i = 0;
  for (auto &op : ops) {
    matrix<Complex> S(G.G.r);
    // build the operator matrix
    for (auto &x : op->GF_elem)
      S(x.r, x.c) += x.v;
    for (auto &x : op->IGF_elem)
      S(x.r, x.c) += x.v * K.phase[x.n];
    matrix<Complex> S_per = model->periodize(k_red, S);
    I[i++] = realpart(K.g.trace_product(S_per));
  }
  i = 0;
  if (model->mixing == HS_mixing::up_down) {
    Green_function G = cluster_Green_function(w, false, true);
    Green_function_k K(G, k_red);
    periodized_Green_function(K);
    K.g.add(-G_pole); // regulates the Green function at high frequency
                      // (subtracts G_pole times the identity matrix)
    for (auto &op : ops) {
      matrix<Complex> S(G.G.r);
      // build the operator matrix
      for (auto &x : op->GF_elem_down)
        S(x.r, x.c) += x.v;
      for (auto &x : op->IGF_elem_down)
        S(x.r, x.c) += x.v * K.phase[x.n];
      matrix<Complex> S_per = model->periodize(k_red, S);
      I[i++] += realpart(K.g.trace_product(S_per));
    }
  }
  if (model->mixing == HS_mixing::normal)
    for (size_t i = 0; i < ops.size(); i++)
      I[i] *= 2;
}

