/**
 calculates the density of states
 In the anomalous case, this function will compute the DoS at the opposite
 frequency (-w) for the spin down part.

 @param w frequency
 returns an array of dimension 2*n_band
 */
vector<double> lattice_model_instance::dos(const complex<double> w) {
  double accur_OP = global_double("accur_OP");
  if (!gf_solved)
    Green_function_solve();

  size_t D_dim = model->n_band;
  size_t d = D_dim;
  if (model->mixing & 3)
    d *= 2;
  vector<double> D(2 * D_dim);

  Green_function G = cluster_Green_function(w, false, false);

  auto F = [this, G](vector3D<double> &k, const int *nv, double *I) mutable {
    for (size_t i = 0; i < *nv; i++)
      I[i] = 0.0;
    Green_function_k K(G, k);
    set_Gcpt(K);
    for (size_t i = 0; i < model->dim_GF; i++)
      I[model->reduced_Green_index[i]] += K.Gcpt(i, i).imag();
  };

  vector<double> Iv(model->dim_reduced_GF, 0.0);
  QCM::k_integral(model->spatial_dimension, F, Iv, accur_OP,
                  global_bool("verb_integrals"));
  for (size_t i = 0; i < d; i++)
    D[i] = -M_1_PI * Iv[i] / model->Lc;

  if (model->mixing == HS_mixing::up_down) {
    Green_function G_down = cluster_Green_function(w, false, true);

    auto F_down = [this, G_down](vector3D<double> &k, const int *nv,
                                 double *I) mutable {
      for (size_t i = 0; i < *nv; i++)
        I[i] = 0.0;
      Green_function_k K(G_down, k);
      set_Gcpt(K);
      for (size_t i = 0; i < model->dim_GF; i++)
        I[model->reduced_Green_index[i]] += K.Gcpt(i, i).imag();
    };

    to_zero(Iv);
    QCM::k_integral(model->spatial_dimension, F_down, Iv, accur_OP,
                    global_bool("verb_integrals"));
    for (size_t i = 0; i < D_dim; i++)
      D[i + D_dim] = -M_1_PI * Iv[i] / model->Lc;
  } else if (model->mixing == HS_mixing::normal) {
    for (size_t i = 0; i < D_dim; i++)
      D[i + D_dim] = D[i];
  }
  return D;
}

