/**
 calculates the contribution of a frequency to the average of the operator
 'name'
 @param name [in] name of the operator
 @param w [in] complex frequency
 */
double lattice_model_instance::spectral_average(const string &name,
                                                const complex<double> w) {
  double accur_OP = global_double("accur_OP");
  if (model->term.find(name) == model->term.end())
    qcm_throw("the operator " + name + " does not exist");

  lattice_operator op = *model->term.at(name);

  if (!gf_solved)
    Green_function_solve();

  Green_function G = cluster_Green_function(w, false, false);

  auto F = [this, op, G](vector3D<double> &k, const int *nv,
                         double *I) mutable {
    for (size_t i = 0; i < *nv; i++)
      I[i] = 0.0;
    Green_function_k K(G, k);
    set_Gcpt(K);
    Complex z(0.0);
    for (auto &x : op.GF_elem)
      z += K.Gcpt(x.c, x.r) * x.v;
    for (auto &x : op.IGF_elem)
      z += K.Gcpt(x.c, x.r) * x.v * K.phase[x.n] +
           K.Gcpt(x.r, x.c) * conjugate(x.v * K.phase[x.n]);
    I[0] = imag(z);
  };
  vector<double> Iv(1, 0.0);
  QCM::k_integral(model->spatial_dimension, F, Iv, accur_OP,
                  global_bool("verb_integrals"));

  double result = -M_1_PI * Iv[0] / model->Lc;

  if (model->mixing == HS_mixing::up_down) {
    Green_function G_down = cluster_Green_function(w, false, true);
    G_down.w = w;
    G_down.spin_down = true;
    G_down.G.block.assign(n_clus, matrix<Complex>());
    for (size_t i = 0; i < n_clus; i++) {
      G_down.G.block[i] = matrix<Complex>(
          model->GF_dims[i],
          ED::Green_function(w, true, n_clus * label + model->clusters[i].ref,
                             false));
    }
    G_down.G.set_size();

    auto F_down = [this, G_down, op](vector3D<double> &k, const int *nv,
                                     double *I) mutable {
      for (size_t i = 0; i < *nv; i++)
        I[i] = 0.0;
      Green_function_k K(G_down, k);
      set_Gcpt(K);
      Complex z(0.0);
      for (auto &x : op.GF_elem)
        z += K.Gcpt(x.c, x.r) * x.v;
      for (auto &x : op.IGF_elem)
        z += K.Gcpt(x.c, x.r) * x.v * K.phase[x.n] +
             K.Gcpt(x.r, x.c) * conjugate(x.v * K.phase[x.n]);
      I[0] = imag(z);
    };

    to_zero(Iv);
    QCM::k_integral(model->spatial_dimension, F_down, Iv, accur_OP,
                    global_bool("verb_integrals"));
    result += -M_1_PI * Iv[0] / model->Lc;
  }
  if (model->mixing == HS_mixing::normal)
    result *= 2;

  return result;
}

