/** calculates the momentum-dependent average of an operator
 @param op [in] lattice operator
 @param k_set [in] array of wavevectors
 @returns an array of average values, one for each wavevector
 */
vector<double> lattice_model_instance::momentum_profile(
    const lattice_operator &op, const vector<vector3D<double>> &k_set) {
  double accur_OP = global_double("accur_OP");
  auto Fmp = [this, k_set, op](Complex w, vector3D<double> &ki, const int *nv,
                               double *I) mutable {
    const double w_offset = 2.0;
    Complex G_pole = 1.0 / (w - w_offset);

    Green_function G = cluster_Green_function(w, false, false);
    size_t i = 0;
    for (auto &k : k_set) {
      Green_function_k K(G, k);
      set_Gcpt(K);
      K.Gcpt.add(-G_pole); // regulates the Green function at high frequency
                           // (subtracts G_pole times the identity matrix)
      Complex z(0.0);
      for (auto &x : op.GF_elem)
        z += K.Gcpt(x.c, x.r) * x.v;
      for (auto &x : op.IGF_elem)
        z += K.Gcpt(x.c, x.r) * x.v * K.phase[x.n];
      I[i++] = real<double>(z);
    }
    if (model->mixing == HS_mixing::up_down) {
      Green_function G_dw = cluster_Green_function(w, false, true);
      i = 0;
      for (auto &k : k_set) {
        Green_function_k K(G_dw, k);
        set_Gcpt(K);
        K.Gcpt.add(-G_pole); // regulates the Green function at high frequency
                             // (subtracts G_pole times the identity matrix)
        Complex z(0.0);
        for (auto &x : op.GF_elem)
          z += K.Gcpt(x.c, x.r) * x.v;
        for (auto &x : op.IGF_elem)
          z += K.Gcpt(x.c, x.r) * x.v * K.phase[x.n];
        I[i++] += real<double>(z);
      }
    }
  };
  vector<double> A(k_set.size(), 0.0);
  QCM::wk_integral(0, Fmp, A, accur_OP, global_bool("verb_integrals"));
  if (model->mixing == HS_mixing::normal)
    A *= 2;
  else if ((model->mixing & HS_mixing::anomalous) == HS_mixing::anomalous)
    A += op.nambu_correction;
  else if (model->mixing == HS_mixing::full) {
    A += op.nambu_correction_full;
    A *= 0.5;
  }
  A *= op.norm;
  return A;
}

