//==============================================================================
/** Calculates the potential energy using $V = Tr(\Sigma G)$
 The self-energy cannot be accurately computed when the frequency is too high,
 because of round off errors when subtracting the frequency from the inverse
 Green function. Best to not go beyond half the accuracy of doubles, i.e., 1e-7
 (or freq ~ 1e7).
 @returns the potential energy
 */
double lattice_model_instance::potential_energy() {
  if (PE_solved)
    return E_pot;
  PE_solved = true;

  double accur_OP = global_double("accur_OP");
  if (!gf_solved)
    Green_function_solve();

  // computing the infinite frequency limit
  double prev_cutoff = global_double("cutoff_scale");
  set_global_double("cutoff_scale", WINF); // important for convergence

  tr_sigma_inf = 0.0;
  for (int i = 0; i < model->clusters.size(); i++) {
    tr_sigma_inf += ED::tr_sigma_inf(i + label * model->clusters.size());
  }

  // frequency integral
  vector<double> I(1);
  // lambda function
  auto F = [this](Complex w, vector3D<double> &k, const int *nv,
                  double *I) mutable {
    potential_energy_integrand(w, k, nv, I);
  };
  QCM::wk_integral(model->spatial_dimension, F, I, 0.1 * accur_OP,
                   global_bool("verb_integrals"));

  set_global_double("cutoff_scale", prev_cutoff); // restores to previous value
  if (model->mixing == HS_mixing::full)
    I[0] *= 0.5; // full Nambu doubling overestimates by a factor of 2
  E_pot = 0.5 * I[0] / model->Lc;
  return E_pot;
}

//==============================================================================
/** computes Tr(Sigma G) at a given frequency and wavevector, for the
 computation of the potential energy
 @param w frequency
 @param k wavevector
 @param spin_down true if in spin down sector (mixing = 4)
 @returns Tr(Sigma G)
 */
complex<double> lattice_model_instance::TrSigmaG(Complex w, vector3D<double> &k,
                                                 bool spin_down) {
  complex<double> z(0.0);
  Green_function G = cluster_Green_function(w, false, spin_down);
  Green_function_k K(G, k);
  set_Gcpt(K);
  cluster_self_energy(G);
  z = G.sigma.build_matrix().trace_product(K.Gcpt);
  return z;
}

//==============================================================================
/** integrand in the computation of the potential energy
 @param w frequency
 @param k wavevector
 @param nv number of components
 @param I values of the components of the integrand
 */
void lattice_model_instance::potential_energy_integrand(Complex w,
                                                        vector3D<double> &k,
                                                        const int *nv,
                                                        double *I) {
  check_signals();

  const double w_offset = 2.0;

  Complex e = TrSigmaG(w, k, false);
  if (model->mixing == HS_mixing::up_down)
    e += TrSigmaG(w, k, true);
  else if (model->mixing == HS_mixing::normal)
    e *= 2;

  e -= tr_sigma_inf / (w - w_offset);
  I[0] = real<double>(e);
}
